const raw = $input.first().json;
const body = raw.body || raw;

const data = body.data || {};
const key = data.key || {};
const msg = data.message || {};

const text =
  msg.conversation ||
  msg?.extendedTextMessage?.text ||
  msg?.imageMessage?.caption ||
  msg?.videoMessage?.caption ||
  msg?.documentMessage?.caption ||
  '';

const remoteJid = key.remoteJid || '';
const fromMe = key.fromMe || false;
const instance = body.instance || 'Teste';

if (fromMe || !text.trim()) return [];
if (remoteJid.includes('@g.us')) return [];

const phone = remoteJid
  .replace('@s.whatsapp.net', '')
  .replace('@c.us', '');

return [{ json: { text: text.trim(), phone, remoteJid, instance } }];

const input = $input.first().json;
const text = (input.text || '').toLowerCase();
const now = new Date();
const fmt = d => d.toISOString().split('T')[0];
const addDays = (n) => { const d = new Date(now); d.setDate(d.getDate() + n); return fmt(d); };
const dow = now.getDay();
const daysToMon = dow === 0 ? 6 : dow - 1;
const monday = new Date(now);
monday.setDate(now.getDate() - daysToMon);

const clientMap = {
  'antonio neto': { id: 'act_497795903676192', nome: 'Antonio Neto' },
  'antonio': { id: 'act_497795903676192', nome: 'Antonio Neto' },
  'gabriel jacinto': { id: 'act_2493856707309984', nome: 'Gabriel Jacinto' },
  'gabriel': { id: 'act_2493856707309984', nome: 'Gabriel Jacinto' },
  'dani escudero': { id: 'act_2145598605527232', nome: 'Dani Escudero' },
  'dani': { id: 'act_2145598605527232', nome: 'Dani Escudero' },
  'agro': { id: 'act_929521557422139', nome: 'Agro' },
  'escola de musica': { id: 'act_544347952854095', nome: 'Escola de M\u00fasica' },
  'escola de m\u00fasica': { id: 'act_544347952854095', nome: 'Escola de M\u00fasica' },
  'escola': { id: 'act_544347952854095', nome: 'Escola de M\u00fasica' },
  'panmalhas': { id: 'act_1509005182799187', nome: 'Panmalhas Assessoria T\u00eaxtil' },
  'gfix store': { id: 'act_2811791829124905', nome: 'GFiX Store' },
  'gfix': { id: 'act_2811791829124905', nome: 'GFiX Store' },
  'arte em gelo': { id: 'act_5585082641598366', nome: 'Arte em Gelo' },
  'arte em gelo': { id: 'act_5585082641598366', nome: 'Arte em Gelo' },
  'itag tecnologia': { id: 'act_738466861151636', nome: 'ITAG Tecnologia' },
  'itag': { id: 'act_738466861151636', nome: 'ITAG Tecnologia' },
  'hi dogz': { id: 'act_873195821346004', nome: 'Hi Dogz' },
  'dogz': { id: 'act_873195821346004', nome: 'Hi Dogz' },
  'batata bistro': { id: 'act_1673012226810411', nome: 'Batata Bistr\u00f4' },
  'batata bistr\u00f4': { id: 'act_1673012226810411', nome: 'Batata Bistr\u00f4' },
  'batata': { id: 'act_1673012226810411', nome: 'Batata Bistr\u00f4' },
  'caribbean bronze': { id: 'act_1082397873705862', nome: 'Caribbean Bronze' },
  'caribbean': { id: 'act_1082397873705862', nome: 'Caribbean Bronze' },
  'larissa kelleter': { id: 'act_738280412237298', nome: 'Larissa Kelleter' },
  'larissa': { id: 'act_738280412237298', nome: 'Larissa Kelleter' }
};

// Detecta pedido de relatório sem exigir a palavra 'semanal'
const isRelatorio = text.includes('relat');

let clientFound = null;
const sortedKeys = Object.keys(clientMap).sort((a, b) => b.length - a.length);
for (const key of sortedKeys) {
  if (text.includes(key)) {
    clientFound = clientMap[key];
    break;
  }
}

const today = fmt(now);
const yesterday = addDays(-1);
const last7Start = addDays(-7);
const isRelatorioWithClient = isRelatorio && clientFound !== null;

return [{
  json: {
    ...input,
    today,
    yesterday,
    weekStart: fmt(monday),
    last7: last7Start,
    last30: addDays(-30),
    last7Start,
    last7End: yesterday,
    metaToken: 'EAAeVLzZANk8oBQ79Ue5UimCCCYL9uNZCH9EZA7vZAJtqB5B9aQ6mO53EnUI1b8Cskpq9tRsYZAaDKvZB1kLZABjbqgwi3aenhyPnAtQkeineasNmaZA7vue9ndlaErc59UFZBaMBeDnBC8ZBpXtn9PdUP4OMQvkd53QZAL1jI9SC49WGZCvgopdZABkhGKCEuVStyYGRfYPrlhksx7HHkqZBNWo5gMLhREik5hvkp1JA7X',
    isRelatorio,
    isRelatorioWithClient,
    clientFound: clientFound ? clientFound.id : null,
    clientNome: clientFound ? clientFound.nome : null
  }
}];

const metaData = $input.first().json;
const ctx = $('Calcular Datas').first().json;
const campaigns = metaData.data || [];

if (!campaigns.length) {
  return [{ json: { ...ctx, output: '\u274c Sem dados para *' + (ctx.clientNome || '').toUpperCase() + '* nos \u00faltimos 7 dias.' } }];
}

// Contas de compra direta (e-commerce / vendas)
const purchaseAccountIds = ['act_873195821346004', 'act_1673012226810411']; // Hi Dogz, Batata Bistr\u00f4
const isPurchase = purchaseAccountIds.includes(ctx.clientFound);

const fmtBR = (dateStr) => {
  const d = new Date(dateStr + 'T12:00:00Z');
  return String(d.getUTCDate()).padStart(2, '0') + '/' + String(d.getUTCMonth() + 1).padStart(2, '0');
};

const fmtMoney = (val) => {
  return val.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
};

const fmtNum = (val) => {
  return parseInt(val || 0).toLocaleString('pt-BR');
};

let totalSpend = 0;
let totalImpressions = 0;
let totalClicks = 0;

for (const c of campaigns) {
  totalSpend += parseFloat(c.spend || '0');
  totalImpressions += parseInt(c.impressions || '0');
  totalClicks += parseInt(c.clicks || '0');
}

const clientNameUpper = (ctx.clientNome || '').toUpperCase();
let reportText;

if (isPurchase) {
  let totalPurchases = 0;
  for (const c of campaigns) {
    const purchaseAction = (c.actions || []).find(a =>
      a.action_type === 'purchase' ||
      a.action_type === 'offsite_conversion.fb_pixel_purchase'
    );
    if (purchaseAction) totalPurchases += parseInt(purchaseAction.value);
  }
  const cpp = totalPurchases > 0 ? totalSpend / totalPurchases : 0;
  reportText =
    '*' + clientNameUpper + '*\n\n' +
    '_\ud83d\udcc6 ' + fmtBR(ctx.last7Start) + ' a ' + fmtBR(ctx.last7End) + ' (\u00faltimos 7 dias)_\n\n' +
    '*Meta Ads*\n\n' +
    'Impress\u00f5es: ' + fmtNum(totalImpressions) + '\n\n' +
    'Cliques: ' + fmtNum(totalClicks) + '\n\n' +
    'Vendas: ' + totalPurchases + '\n\n' +
    'Custo por venda: R$ ' + fmtMoney(cpp) + '\n\n' +
    '*INVESTIMENTO TOTAL: R$ ' + fmtMoney(totalSpend) + '*';
} else {
  const LEAD_TYPES = [
    'lead',
    'onsite_conversion.lead_grouped',
    'onsite_conversion.messaging_conversation_started_7d',
    'onsite_conversion.total_messaging_connection'
  ];

  let leadSpend = 0;
  let totalLeads = 0;
  for (const c of campaigns) {
    const leadAction = (c.actions || []).find(a => LEAD_TYPES.includes(a.action_type));
    if (leadAction) {
      leadSpend += parseFloat(c.spend || '0');
      totalLeads += parseInt(leadAction.value);
    }
  }
  const cpl = totalLeads > 0 ? leadSpend / totalLeads : 0;
  reportText =
    '*' + clientNameUpper + '*\n\n' +
    '_\ud83d\udcc6 ' + fmtBR(ctx.last7Start) + ' a ' + fmtBR(ctx.last7End) + ' (\u00faltimos 7 dias)_\n\n' +
    '*Meta Ads*\n\n' +
    'Impress\u00f5es: ' + fmtNum(totalImpressions) + '\n\n' +
    'Cliques: ' + fmtNum(totalClicks) + '\n\n' +
    'Leads: ' + totalLeads + '\n\n' +
    'Custo por lead: R$ ' + fmtMoney(cpl) + '\n\n' +
    '*INVESTIMENTO TOTAL: R$ ' + fmtMoney(totalSpend) + '*';
}

return [{ json: { ...ctx, output: reportText } }];

const metaResp = $input.first().json;
const ctx = $('Calcular Datas').first().json;
const allAccounts = metaResp.data || [];
const accountsList = allAccounts.map(a => {
  const status = a.account_status === 1 ? '\u2705 Ativa' : '\u23f8 Inativa';
  return '\u2022 ' + a.name + ' | ID: ' + a.id + ' | ' + a.currency + ' | ' + status;
}).join('\n') || 'Nenhuma conta encontrada';
return [{ json: { ...ctx, accounts: allAccounts, accountsList } }];

let params;
try { params = JSON.parse(query); } catch(e) { return 'Erro: envie JSON com object_id e date_preset'; }
const token = 'EAAeVLzZANk8oBQ79Ue5UimCCCYL9uNZCH9EZA7vZAJtqB5B9aQ6mO53EnUI1b8Cskpq9tRsYZAaDKvZB1kLZABjbqgwi3aenhyPnAtQkeineasNmaZA7vue9ndlaErc59UFZBaMBeDnBC8ZBpXtn9PdUP4OMQvkd53QZAL1jI9SC49WGZCvgopdZABkhGKCEuVStyYGRfYPrlhksx7HHkqZBNWo5gMLhREik5hvkp1JA7X';
const objectId = params.object_id;
const datePreset = params.date_preset || 'today';
const fields = params.fields || 'spend,impressions,clicks,ctr,cpc,actions,reach,cost_per_action_type';
const level = params.level || '';
if (!objectId) return 'Erro: object_id é obrigatório';
let url = `https://graph.facebook.com/v19.0/${objectId}/insights?date_preset=${encodeURIComponent(datePreset)}&fields=${encodeURIComponent(fields)}&access_token=${token}`;
if (level) url += `&level=${encodeURIComponent(level)}`;
try {
  const res = await fetch(url);
  const data = await res.json();
  if (data.error) return `Erro Meta API: ${data.error.message} (código: ${data.error.code})`;
  if (!data.data || data.data.length === 0) return 'Nenhum dado encontrado para o período solicitado.';
  return JSON.stringify(data.data);
} catch(e) { return `Erro de conexão: ${e.message}`; }

let params;
try { params = JSON.parse(query); } catch(e) { return 'Erro: envie JSON com account_id'; }
const token = 'EAAeVLzZANk8oBQ79Ue5UimCCCYL9uNZCH9EZA7vZAJtqB5B9aQ6mO53EnUI1b8Cskpq9tRsYZAaDKvZB1kLZABjbqgwi3aenhyPnAtQkeineasNmaZA7vue9ndlaErc59UFZBaMBeDnBC8ZBpXtn9PdUP4OMQvkd53QZAL1jI9SC49WGZCvgopdZABkhGKCEuVStyYGRfYPrlhksx7HHkqZBNWo5gMLhREik5hvkp1JA7X';
const accountId = params.account_id;
if (!accountId) return 'Erro: account_id é obrigatório (formato: act_XXXXXXXXX)';
try {
  const url = `https://graph.facebook.com/v19.0/${accountId}/campaigns?fields=id,name,status,objective,daily_budget,lifetime_budget&limit=100&access_token=${token}`;
  const res = await fetch(url);
  const data = await res.json();
  if (data.error) return `Erro Meta API: ${data.error.message}`;
  if (!data.data || data.data.length === 0) return 'Nenhuma campanha encontrada nessa conta';
  const campaigns = data.data.map(c => ({
    id: c.id,
    nome: c.name,
    status: c.status,
    objetivo: c.objective,
    budget_diario_reais: c.daily_budget ? (parseInt(c.daily_budget) / 100).toFixed(2) : null,
    budget_total_reais: c.lifetime_budget ? (parseInt(c.lifetime_budget) / 100).toFixed(2) : null
  }));
  return JSON.stringify(campaigns);
} catch(e) { return `Erro de conexão: ${e.message}`; }

let params;
try { params = JSON.parse(query); } catch(e) { return 'Erro: envie JSON com account_id ou campaign_id'; }
const token = 'EAAeVLzZANk8oBQ79Ue5UimCCCYL9uNZCH9EZA7vZAJtqB5B9aQ6mO53EnUI1b8Cskpq9tRsYZAaDKvZB1kLZABjbqgwi3aenhyPnAtQkeineasNmaZA7vue9ndlaErc59UFZBaMBeDnBC8ZBpXtn9PdUP4OMQvkd53QZAL1jI9SC49WGZCvgopdZABkhGKCEuVStyYGRfYPrlhksx7HHkqZBNWo5gMLhREik5hvkp1JA7X';
const accountId = params.account_id;
const campaignId = params.campaign_id;
if (!accountId && !campaignId) return 'Erro: forneça account_id ou campaign_id';
const baseId = campaignId || accountId;
try {
  const url = `https://graph.facebook.com/v19.0/${baseId}/adsets?fields=id,name,status,daily_budget,lifetime_budget,campaign_id&limit=100&access_token=${token}`;
  const res = await fetch(url);
  const data = await res.json();
  if (data.error) return `Erro Meta API: ${data.error.message}`;
  if (!data.data || data.data.length === 0) return 'Nenhum conjunto de anúncios encontrado';
  const adsets = data.data.map(a => ({
    id: a.id,
    nome: a.name,
    status: a.status,
    budget_diario_reais: a.daily_budget ? (parseInt(a.daily_budget) / 100).toFixed(2) : null,
    budget_total_reais: a.lifetime_budget ? (parseInt(a.lifetime_budget) / 100).toFixed(2) : null
  }));
  return JSON.stringify(adsets);
} catch(e) { return `Erro de conexão: ${e.message}`; }

let params;
try { params = JSON.parse(query); } catch(e) { return 'Erro: envie JSON com account_ids (array), date_preset e fields'; }
const token = 'EAAeVLzZANk8oBQ79Ue5UimCCCYL9uNZCH9EZA7vZAJtqB5B9aQ6mO53EnUI1b8Cskpq9tRsYZAaDKvZB1kLZABjbqgwi3aenhyPnAtQkeineasNmaZA7vue9ndlaErc59UFZBaMBeDnBC8ZBpXtn9PdUP4OMQvkd53QZAL1jI9SC49WGZCvgopdZABkhGKCEuVStyYGRfYPrlhksx7HHkqZBNWo5gMLhREik5hvkp1JA7X';
const accountIds = params.account_ids || [];
const datePreset = params.date_preset || 'today';
const fields = params.fields || 'spend,impressions,clicks,actions,reach';
if (accountIds.length === 0) return 'Erro: account_ids deve ser um array com pelo menos 1 conta';
try {
  const results = [];
  for (const accountId of accountIds) {
    const url = `https://graph.facebook.com/v19.0/${accountId}/insights?date_preset=${encodeURIComponent(datePreset)}&fields=${encodeURIComponent(fields)}&access_token=${token}`;
    const res = await fetch(url);
    const data = await res.json();
    if (!data.error && data.data && data.data.length > 0) {
      results.push({ account_id: accountId, data: data.data[0] });
    } else if (data.error) {
      results.push({ account_id: accountId, error: data.error.message });
    } else {
      results.push({ account_id: accountId, data: null, note: 'sem dados no período' });
    }
  }
  return JSON.stringify(results);
} catch(e) { return `Erro de conexão: ${e.message}`; }
